import { useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { getCalendarDays } from '../utils/dateUtils';
import { DAY_LABELS } from '../utils/constants';
import DayCell from './DayCell';
import MonthNavigator from './MonthNavigator';

/**
 * CalendarGrid renders the full month view:
 * - Month navigator (prev/next/today)
 * - Day-of-week headers
 * - 6├ù7 grid of DayCell components
 */
export default function CalendarGrid({
  currentMonth,
  currentYear,
  rangeStart,
  rangeEnd,
  hoverDate,
  selectionMode,
  notes,
  onDateClick,
  onDateHover,
  onDateHoverEnd,
  onPrevMonth,
  onNextMonth,
  onToday,
  onResetSelection,
  selectedDates,
}) {
  const days = useMemo(
    () => getCalendarDays(currentYear, currentMonth),
    [currentYear, currentMonth]
  );

  return (
    <div className="glass rounded-2xl lg:rounded-3xl p-4 sm:p-5 lg:p-6" id="calendar-grid">
      {/* Navigation */}
      <MonthNavigator
        month={currentMonth}
        year={currentYear}
        onPrev={onPrevMonth}
        onNext={onNextMonth}
        onToday={onToday}
      />

      {/* Selection info bar */}
      <AnimatePresence>
        {selectionMode !== 'idle' && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            className="overflow-hidden"
          >
            <div className="flex items-center justify-between mb-3 px-2 py-1.5 rounded-lg bg-indigo-500/10 border border-indigo-500/20">
              <span className="text-xs text-indigo-300">
                {selectionMode === 'selecting'
                  ? '≡ƒÄ» Click another date to complete range'
                  : `Γ£à ${selectedDates.length} day${selectedDates.length > 1 ? 's' : ''} selected`}
              </span>
              <button
                onClick={onResetSelection}
                className="text-xs text-white/50 hover:text-white/80 transition-colors px-2 py-0.5 rounded hover:bg-white/5"
                id="btn-clear-selection"
              >
                Clear
              </button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Day-of-week headers */}
      <div className="grid grid-cols-7 mb-1.5">
        {DAY_LABELS.map((label) => (
          <div
            key={label}
            className="text-center text-[11px] font-semibold text-white/30 uppercase tracking-wider py-2"
          >
            {label}
          </div>
        ))}
      </div>

      {/* Days grid with animated transitions */}
      <AnimatePresence mode="wait">
        <motion.div
          key={`${currentMonth}-${currentYear}`}
          initial={{ opacity: 0, x: 30 }}
          animate={{ opacity: 1, x: 0 }}
          exit={{ opacity: 0, x: -30 }}
          transition={{ duration: 0.3, ease: 'easeInOut' }}
          className="grid grid-cols-7 gap-0.5 sm:gap-1"
        >
          {days.map((date) => (
            <DayCell
              key={date.toISOString()}
              date={date}
              currentMonth={currentMonth}
              currentYear={currentYear}
              rangeStart={rangeStart}
              rangeEnd={rangeEnd}
              hoverDate={hoverDate}
              selectionMode={selectionMode}
              notes={notes}
              onClick={onDateClick}
              onHover={onDateHover}
              onHoverEnd={onDateHoverEnd}
            />
          ))}
        </motion.div>
      </AnimatePresence>
    </div>
  );
}

import { memo } from 'react';
import { motion } from 'framer-motion';
import {
  isSameMonth,
  isToday,
  isSameDay,
  isWeekend,
  format,
  isInRange,
  isRangeStart,
  isRangeEnd,
  dateKey,
} from '../utils/dateUtils';

/**
 * DayCell ΓÇö individual grid cell in the calendar.
 * Visual states: today, selected, range start/middle/end, weekend, has-note.
 * Features tooltip preview on hover when a note exists.
 */
const DayCell = memo(function DayCell({
  date,
  currentMonth,
  currentYear,
  rangeStart,
  rangeEnd,
  hoverDate,
  selectionMode,
  notes,
  onClick,
  onHover,
  onHoverEnd,
}) {
  const inMonth = isSameMonth(date, new Date(currentYear, currentMonth, 1));
  const today = isToday(date);
  const weekend = isWeekend(date);
  const key = dateKey(date);
  const hasNote = !!notes[key];
  const noteText = notes[key] || '';
  const dayNum = format(date, 'd');

  // Determine range states
  const effectiveEnd = selectionMode === 'selecting' && hoverDate ? hoverDate : rangeEnd;
  const inRange = rangeStart && effectiveEnd ? isInRange(date, rangeStart, effectiveEnd) : false;
  const isStart = rangeStart && effectiveEnd ? isRangeStart(date, rangeStart, effectiveEnd) : false;
  const isEnd = rangeStart && effectiveEnd ? isRangeEnd(date, rangeStart, effectiveEnd) : false;
  const isSingleSelect = rangeStart && !rangeEnd && !hoverDate && isSameDay(date, rangeStart);
  const isHoverPreview = selectionMode === 'selecting' && hoverDate && inRange && !isStart;

  // Build class names
  let cellClasses = 'relative w-full aspect-square flex items-center justify-center rounded-xl text-sm font-medium transition-all duration-200 cursor-pointer select-none ';

  if (!inMonth) {
    cellClasses += 'text-white/10 cursor-default ';
  } else if (today && !inRange && !isSingleSelect) {
    cellClasses += 'bg-amber-500 text-white shadow-lg shadow-amber-500/25 font-bold ';
  } else if (isStart || isEnd || isSingleSelect) {
    cellClasses += 'bg-indigo-500 text-white shadow-lg shadow-indigo-500/30 font-semibold ring-2 ring-indigo-400/30 ';
  } else if (inRange) {
    cellClasses += 'bg-indigo-500/15 text-indigo-300 ';
  } else if (weekend) {
    cellClasses += 'text-white/35 hover:bg-white/[0.04] ';
  } else {
    cellClasses += 'text-white/65 hover:bg-white/[0.04] ';
  }

  // Tooltip class for note preview
  const tooltipClass = hasNote && inMonth ? 'tooltip' : '';

  return (
    <motion.button
      whileHover={inMonth ? { scale: 1.1 } : {}}
      whileTap={inMonth ? { scale: 0.9 } : {}}
      onClick={() => inMonth && onClick(date)}
      onMouseEnter={() => inMonth && onHover(date)}
      onMouseLeave={onHoverEnd}
      className={`${cellClasses} ${tooltipClass}`}
      disabled={!inMonth}
      aria-label={inMonth ? `${format(date, 'MMMM d, yyyy')}${hasNote ? ' - has note' : ''}` : undefined}
      id={inMonth ? `day-${key}` : undefined}
      data-tooltip={hasNote ? (noteText.length > 50 ? noteText.substring(0, 50) + 'ΓÇª' : noteText) : undefined}
    >
      {/* Day number */}
      <span className={`relative z-10 ${isHoverPreview ? 'opacity-60' : ''}`}>
        {dayNum}
      </span>

      {/* Note indicator dot */}
      {hasNote && inMonth && (
        <span
          className="absolute bottom-1 left-1/2 -translate-x-1/2 w-1.5 h-1.5 rounded-full bg-emerald-400 shadow-sm shadow-emerald-400/50 note-pulse"
          aria-hidden="true"
        />
      )}

      {/* Today ring overlay when part of a range */}
      {today && (inRange || isSingleSelect) && (
        <span className="absolute inset-0 rounded-xl ring-2 ring-amber-400/50" aria-hidden="true" />
      )}
    </motion.button>
  );
});

export default DayCell;

import { motion, AnimatePresence } from 'framer-motion';
import { MONTH_IMAGES, MONTH_NAMES } from '../utils/constants';
import { useState, useEffect } from 'react';

/**
 * HeroImage ΓÇö full-bleed animated hero with Ken Burns effect.
 * Uses Lorem Picsum URLs (always loads).
 * Has gradient fallback background even if image is loading/failed.
 */
export default function HeroImage({ month, year }) {
  const imageData = MONTH_IMAGES[month];
  const [loaded, setLoaded] = useState(false);

  useEffect(() => {
    setLoaded(false);
  }, [month]);

  return (
    <div className="relative w-full h-full overflow-hidden rounded-2xl lg:rounded-3xl shadow-2xl shadow-black/30">
      {/* Always-visible fallback gradient background */}
      <div className={`absolute inset-0 bg-gradient-to-br ${imageData.fallbackBg}`} />

      <AnimatePresence mode="wait">
        <motion.div
          key={month}
          initial={{ opacity: 0, scale: 1.08 }}
          animate={{ opacity: 1, scale: 1 }}
          exit={{ opacity: 0, scale: 0.97 }}
          transition={{ duration: 0.7, ease: [0.25, 0.46, 0.45, 0.94] }}
          className="absolute inset-0"
        >
          {/* The actual image */}
          <img
            src={imageData.src}
            alt={imageData.alt}
            loading="eager"
            crossOrigin="anonymous"
            onLoad={() => setLoaded(true)}
            className={`absolute inset-0 w-full h-full object-cover transition-opacity duration-700 ${
              loaded ? 'opacity-100' : 'opacity-0'
            }`}
            style={{ animation: loaded ? 'kenBurns 30s ease-in-out infinite' : 'none' }}
          />

          {/* Gradient overlays */}
          <div className={`absolute inset-0 bg-gradient-to-t ${imageData.gradient}`} />
          <div className="absolute inset-0 bg-gradient-to-r from-black/50 via-transparent to-transparent" />
          <div className="absolute inset-0 bg-gradient-to-b from-transparent via-transparent to-black/60" />

          {/* Month & Year text */}
          <div className="absolute bottom-0 left-0 right-0 p-5 sm:p-6 lg:p-8">
            <motion.div
              initial={{ y: 24, opacity: 0 }}
              animate={{ y: 0, opacity: 1 }}
              transition={{ delay: 0.3, duration: 0.5 }}
            >
              <h1
                className="text-2xl sm:text-3xl lg:text-5xl xl:text-6xl font-bold text-white tracking-tight"
                style={{ fontFamily: 'var(--font-display)', textShadow: '0 2px 20px rgba(0,0,0,0.5)' }}
              >
                {MONTH_NAMES[month]}
              </h1>
              <p className="text-white/60 text-sm sm:text-base lg:text-lg mt-1 font-light tracking-wide">
                {year}
              </p>
            </motion.div>
          </div>
        </motion.div>
      </AnimatePresence>
    </div>
  );
}

import { motion } from 'framer-motion';
import { MONTH_NAMES, MONTH_ACCENTS } from '../utils/constants';

/**
 * MonthNavigator displays the current month/year with
 * previous/next navigation and a "Today" button.
 */
export default function MonthNavigator({
  month,
  year,
  onPrev,
  onNext,
  onToday,
}) {
  const accent = MONTH_ACCENTS[month];

  return (
    <div className="flex items-center justify-between mb-4 sm:mb-5">
      {/* Month & Year */}
      <div className="flex items-center gap-3">
        <motion.h2
          key={`${month}-${year}`}
          initial={{ opacity: 0, y: -10 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.3 }}
          className="text-lg sm:text-xl font-semibold text-white tracking-tight"
          style={{ fontFamily: 'var(--font-display)' }}
        >
          {MONTH_NAMES[month]} {year}
        </motion.h2>

        <motion.button
          whileHover={{ scale: 1.05 }}
          whileTap={{ scale: 0.95 }}
          onClick={onToday}
          className="text-xs px-2.5 py-1 rounded-full bg-white/10 text-white/70 hover:text-white hover:bg-white/15 transition-colors font-medium"
          id="btn-today"
          aria-label="Go to today"
        >
          Today
        </motion.button>
      </div>

      {/* Navigation Arrows */}
      <div className="flex items-center gap-1.5">
        <motion.button
          whileHover={{ scale: 1.1, backgroundColor: 'rgba(255,255,255,0.1)' }}
          whileTap={{ scale: 0.9 }}
          onClick={onPrev}
          className="w-8 h-8 sm:w-9 sm:h-9 rounded-xl flex items-center justify-center text-white/60 hover:text-white transition-colors"
          id="btn-prev-month"
          aria-label="Previous month"
        >
          <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
            <path d="M10 12L6 8L10 4" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
          </svg>
        </motion.button>

        <motion.button
          whileHover={{ scale: 1.1, backgroundColor: 'rgba(255,255,255,0.1)' }}
          whileTap={{ scale: 0.9 }}
          onClick={onNext}
          className="w-8 h-8 sm:w-9 sm:h-9 rounded-xl flex items-center justify-center text-white/60 hover:text-white transition-colors"
          id="btn-next-month"
          aria-label="Next month"
        >
          <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
            <path d="M6 4L10 8L6 12" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
          </svg>
        </motion.button>
      </div>
    </div>
  );
}

import { useState, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { format, dateKey } from '../utils/dateUtils';

/**
 * NotesPanel ΓÇö Add/Edit/Delete notes to selected dates.
 * Desktop: inline card below calendar.
 * Mobile: bottom sheet overlay.
 */
export default function NotesPanel({
  selectedDates,
  notes,
  isOpen,
  onClose,
  onAddNote,
  onEditNote,
  onRemoveNote,
  onAddNoteToAll,
}) {
  const [bulkMode, setBulkMode] = useState(false);
  const [bulkText, setBulkText] = useState('');
  const [editingKey, setEditingKey] = useState(null);
  const [editText, setEditText] = useState('');
  const [newNoteKey, setNewNoteKey] = useState(null);
  const [newNoteText, setNewNoteText] = useState('');

  // ΓöÇΓöÇ Bulk apply ΓöÇΓöÇ
  const handleBulkApply = useCallback(() => {
    if (bulkText.trim()) {
      onAddNoteToAll(bulkText.trim());
      setBulkText('');
      setBulkMode(false);
    }
  }, [bulkText, onAddNoteToAll]);

  // ΓöÇΓöÇ Edit existing ΓöÇΓöÇ
  const startEditing = useCallback((key, currentNote) => {
    setEditingKey(key);
    setEditText(currentNote);
    setNewNoteKey(null);
  }, []);

  const saveEdit = useCallback(() => {
    if (editingKey && editText.trim()) {
      onEditNote(editingKey, editText.trim());
    }
    setEditingKey(null);
    setEditText('');
  }, [editingKey, editText, onEditNote]);

  // ΓöÇΓöÇ Add new ΓöÇΓöÇ
  const startNewNote = useCallback((key) => {
    setNewNoteKey(key);
    setNewNoteText('');
    setEditingKey(null);
  }, []);

  const saveNewNote = useCallback(() => {
    if (newNoteKey && newNoteText.trim()) {
      onAddNote(newNoteKey, newNoteText.trim());
    }
    setNewNoteKey(null);
    setNewNoteText('');
  }, [newNoteKey, newNoteText, onAddNote]);

  // ΓöÇΓöÇ Keyboard shortcuts ΓöÇΓöÇ
  const handleKeyDown = useCallback((e, saveFunc) => {
    if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
      e.preventDefault();
      saveFunc();
    }
  }, []);

  if (!isOpen || !selectedDates || selectedDates.length === 0) return null;

  // ΓöÇΓöÇ Build panel content (shared between desktop & mobile) ΓöÇΓöÇ
  const panelContent = (
    <>
      {/* Header */}
      <div className="flex items-center justify-between px-4 sm:px-5 py-3.5 border-b border-white/[0.06]">
        <div className="flex items-center gap-2.5">
          <div className="w-7 h-7 rounded-lg bg-indigo-500/20 flex items-center justify-center shrink-0">
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" className="text-indigo-400" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <path d="M11 4H4a2 2 0 00-2 2v14a2 2 0 002 2h14a2 2 0 002-2v-7" />
              <path d="M18.5 2.5a2.121 2.121 0 013 3L12 15l-4 1 1-4 9.5-9.5z" />
            </svg>
          </div>
          <div>
            <h3 className="text-sm font-semibold text-white" style={{ fontFamily: 'var(--font-display)' }}>
              Notes
            </h3>
            <p className="text-[10px] text-white/30 leading-tight">
              {selectedDates.length} day{selectedDates.length > 1 ? 's' : ''} selected ┬╖ saved to localStorage
            </p>
          </div>
        </div>
        <button
          onClick={onClose}
          className="w-7 h-7 rounded-lg flex items-center justify-center text-white/25 hover:text-white/70 hover:bg-white/5 transition-all"
          aria-label="Close notes"
        >
          <svg width="12" height="12" viewBox="0 0 16 16" fill="none">
            <path d="M12 4L4 12M4 4L12 12" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
          </svg>
        </button>
      </div>

      {/* Mode toggle for multi-select */}
      {selectedDates.length > 1 && (
        <div className="px-4 sm:px-5 pt-3">
          <div className="flex p-0.5 rounded-xl bg-white/[0.03] border border-white/[0.05]">
            <button
              onClick={() => setBulkMode(false)}
              className={`flex-1 text-[11px] py-1.5 rounded-[10px] font-medium transition-all ${
                !bulkMode ? 'bg-indigo-500/20 text-indigo-300' : 'text-white/30 hover:text-white/50'
              }`}
            >
              Per Day
            </button>
            <button
              onClick={() => setBulkMode(true)}
              className={`flex-1 text-[11px] py-1.5 rounded-[10px] font-medium transition-all ${
                bulkMode ? 'bg-indigo-500/20 text-indigo-300' : 'text-white/30 hover:text-white/50'
              }`}
            >
              Apply to All
            </button>
          </div>
        </div>
      )}

      {/* Bulk input */}
      {bulkMode && (
        <div className="px-4 sm:px-5 py-3">
          <textarea
            autoFocus
            value={bulkText}
            onChange={(e) => setBulkText(e.target.value)}
            onKeyDown={(e) => handleKeyDown(e, handleBulkApply)}
            placeholder="Write a note for all selected days..."
            className="w-full bg-white/[0.04] border border-white/[0.08] rounded-xl px-3 py-2.5 text-sm text-white placeholder-white/20 focus:border-indigo-500/40 focus:outline-none transition-all resize-none"
            rows={3}
          />
          <button
            onClick={handleBulkApply}
            disabled={!bulkText.trim()}
            className="mt-2 w-full text-xs py-2 rounded-xl bg-indigo-500 text-white font-medium hover:bg-indigo-400 transition-all disabled:opacity-20 disabled:cursor-not-allowed"
          >
            Apply to {selectedDates.length} days
          </button>
        </div>
      )}

      {/* Individual notes list */}
      {!bulkMode && (
        <div className="px-4 sm:px-5 py-3 space-y-2.5 max-h-[50vh] lg:max-h-[300px] overflow-y-auto">
          {selectedDates.map((date) => {
            const key = dateKey(date);
            const note = notes[key];
            const isEditing = editingKey === key;
            const isAddingNew = newNoteKey === key;

            return (
              <motion.div
                key={key}
                initial={{ opacity: 0, y: 8 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ duration: 0.2 }}
                className="rounded-xl bg-white/[0.03] border border-white/[0.05] p-3"
              >
                {/* Date label + actions */}
                <div className="flex items-center justify-between mb-1.5">
                  <span className="text-[11px] font-semibold text-white/40 tracking-wide">
                    {format(date, 'EEE, MMM d')}
                  </span>
                  {note && !isEditing && (
                    <div className="flex gap-0.5">
                      <button
                        onClick={() => startEditing(key, note)}
                        className="text-[10px] px-1.5 py-0.5 rounded text-white/20 hover:text-indigo-300 hover:bg-indigo-500/10 transition-all"
                      >
                        Edit
                      </button>
                      <button
                        onClick={() => onRemoveNote(key)}
                        className="text-[10px] px-1.5 py-0.5 rounded text-white/20 hover:text-red-400 hover:bg-red-500/10 transition-all"
                      >
                        Delete
                      </button>
                    </div>
                  )}
                </div>

                {/* Editing existing note */}
                {isEditing ? (
                  <div>
                    <textarea
                      autoFocus
                      value={editText}
                      onChange={(e) => setEditText(e.target.value)}
                      onKeyDown={(e) => handleKeyDown(e, saveEdit)}
                      className="w-full bg-white/[0.04] border border-indigo-500/30 rounded-lg px-3 py-2 text-sm text-white focus:outline-none transition-all resize-none"
                      rows={2}
                    />
                    <div className="flex gap-2 mt-1.5">
                      <button onClick={saveEdit} className="text-[11px] px-3 py-1 rounded-lg bg-indigo-500 text-white font-medium hover:bg-indigo-400 transition-all">
                        Save
                      </button>
                      <button onClick={() => setEditingKey(null)} className="text-[11px] px-3 py-1 rounded-lg bg-white/[0.04] text-white/40 hover:text-white/60 transition-all">
                        Cancel
                      </button>
                      <span className="ml-auto text-[9px] text-white/15 self-center">Ctrl+Enter</span>
                    </div>
                  </div>

                ) : isAddingNew ? (
                  /* Adding new note */
                  <div>
                    <textarea
                      autoFocus
                      value={newNoteText}
                      onChange={(e) => setNewNoteText(e.target.value)}
                      onKeyDown={(e) => handleKeyDown(e, saveNewNote)}
                      placeholder="Write your note..."
                      className="w-full bg-white/[0.04] border border-indigo-500/30 rounded-lg px-3 py-2 text-sm text-white placeholder-white/20 focus:outline-none transition-all resize-none"
                      rows={2}
                    />
                    <div className="flex gap-2 mt-1.5">
                      <button onClick={saveNewNote} disabled={!newNoteText.trim()} className="text-[11px] px-3 py-1 rounded-lg bg-indigo-500 text-white font-medium hover:bg-indigo-400 transition-all disabled:opacity-20">
                        Save
                      </button>
                      <button onClick={() => setNewNoteKey(null)} className="text-[11px] px-3 py-1 rounded-lg bg-white/[0.04] text-white/40 hover:text-white/60 transition-all">
                        Cancel
                      </button>
                      <span className="ml-auto text-[9px] text-white/15 self-center">Ctrl+Enter</span>
                    </div>
                  </div>

                ) : note ? (
                  /* Display saved note */
                  <p className="text-sm text-white/60 leading-relaxed break-words">
                    {note}
                  </p>

                ) : (
                  /* Empty ΓÇö add note button */
                  <button
                    onClick={() => startNewNote(key)}
                    className="w-full text-left text-[11px] text-white/20 hover:text-indigo-300 py-1 transition-all flex items-center gap-1.5"
                  >
                    <svg width="10" height="10" viewBox="0 0 16 16" fill="none">
                      <path d="M8 3v10M3 8h10" stroke="currentColor" strokeWidth="2" strokeLinecap="round" />
                    </svg>
                    Add a note...
                  </button>
                )}
              </motion.div>
            );
          })}
        </div>
      )}
    </>
  );

  return (
    <>
      {/* ΓöÇΓöÇ Desktop: inline card ΓöÇΓöÇ */}
      <motion.div
        initial={{ opacity: 0, y: 16 }}
        animate={{ opacity: 1, y: 0 }}
        exit={{ opacity: 0, y: 16 }}
        transition={{ duration: 0.3 }}
        className="hidden lg:block glass rounded-2xl lg:rounded-3xl overflow-hidden"
      >
        {panelContent}
      </motion.div>

      {/* ΓöÇΓöÇ Mobile: bottom sheet ΓöÇΓöÇ */}
      <motion.div
        initial={{ opacity: 0, y: '100%' }}
        animate={{ opacity: 1, y: 0 }}
        exit={{ opacity: 0, y: '100%' }}
        transition={{ duration: 0.35 }}
        className="lg:hidden fixed inset-x-0 bottom-0 z-50 glass rounded-t-3xl"
        style={{ maxHeight: '70vh' }}
      >
        <div className="flex justify-center pt-2.5 pb-1">
          <div className="w-9 h-1 rounded-full bg-white/15" />
        </div>
        {panelContent}
      </motion.div>

      {/* ΓöÇΓöÇ Mobile backdrop ΓöÇΓöÇ */}
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        onClick={onClose}
        className="lg:hidden fixed inset-0 z-40 bg-black/50 backdrop-blur-sm"
      />
    </>
  );
}

